INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES
(gen_random_uuid(), 'dt', 13, 1, NULL, 'Heinrich Bullinger em Dt 13:1', 'Heinrich Bullinger destaca a centralidade das Escrituras e da graça soberana. Em Deuteronômio 13, o foco recai sobre aliança, santidade e obediência e chama a igreja para justiça com misericórdia. O texto orienta a fé para uma obediência concreta e perseverante. Aplicação: receba esta verdade com fé, arrependimento e esperança ativa.', 'Heinrich Bullinger', 'commentary', '#800080', NOW()),
(gen_random_uuid(), 'dt', 14, 1, NULL, 'Dwight L. Moody em Dt 14:1', 'Dwight L. Moody interpreta este versículo a partir de o chamado ao arrependimento, fé viva e missão. Em Deuteronômio 14, Deus revela aliança, santidade e obediência de forma pastoral e transformadora, promovendo perseverança na tribulação. A verdade bíblica forma caráter, culto e missão. Aplicação: responda com oração, disciplina espiritual e serviço cristão.', 'Dwight L. Moody', 'commentary', '#0E7490', NOW()),
(gen_random_uuid(), 'dt', 15, 1, NULL, 'Joseph Benson em Dt 15:1', 'Joseph Benson destaca a exposição textual com aplicação pastoral objetiva. Em Deuteronômio 15, o foco recai sobre aliança, santidade e obediência e chama a igreja para fidelidade na aliança. O texto orienta a fé para uma obediência concreta e perseverante. Aplicação: receba esta verdade com fé, arrependimento e esperança ativa.', 'Joseph Benson', 'commentary', '#B45309', NOW()),
(gen_random_uuid(), 'dt', 16, 1, NULL, 'Martin Bucer em Dt 16:1', 'Na leitura de Martin Bucer, vemos a centralidade das Escrituras e da graça soberana. Deuteronômio 16 evidencia aliança, santidade e obediência como eixo da vida do povo de Deus, com ênfase em arrependimento sincero. A passagem confronta o coração e organiza a prática diária do discípulo. Aplicação: submeta sua vontade à Palavra e caminhe em fidelidade.', 'Martin Bucer', 'commentary', '#800080', NOW()),
(gen_random_uuid(), 'dt', 17, 1, NULL, 'Charles Finney em Dt 17:1', 'Segundo Charles Finney, o chamado ao arrependimento, fé viva e missão ilumina o sentido deste texto. Deuteronômio 17 mostra que aliança, santidade e obediência sustenta a caminhada da fé, especialmente em esperança escatológica. A doutrina aqui conduz à devoção e à perseverança. Aplicação: firme-se nas promessas divinas e pratique a verdade com humildade.', 'Charles Finney', 'commentary', '#0E7490', NOW()),
(gen_random_uuid(), 'dt', 18, 1, NULL, 'Jamieson-Fausset-Brown em Dt 18:1', 'Na leitura de Jamieson-Fausset-Brown, vemos a exposição textual com aplicação pastoral objetiva. Deuteronômio 18 evidencia aliança, santidade e obediência como eixo da vida do povo de Deus, com ênfase em obediência da fé. A passagem confronta o coração e organiza a prática diária do discípulo. Aplicação: submeta sua vontade à Palavra e caminhe em fidelidade.', 'Jamieson-Fausset-Brown', 'commentary', '#B45309', NOW()),
(gen_random_uuid(), 'dt', 19, 1, NULL, 'John Knox em Dt 19:1', 'John Knox interpreta este versículo a partir de a centralidade das Escrituras e da graça soberana. Em Deuteronômio 19, Deus revela aliança, santidade e obediência de forma pastoral e transformadora, promovendo justiça com misericórdia. A verdade bíblica forma caráter, culto e missão. Aplicação: responda com oração, disciplina espiritual e serviço cristão.', 'John Knox', 'commentary', '#800080', NOW()),
